/* Normalize inbound options
Webhook body (optional):
{
  userId?: string,
  date?: 'YYYY-MM-DD' | ISO,        // any date in the target week; we'll pick that Friday
  lat?: number,
  lon?: number,
  offsets?: { candle?: number, prep?: number, havdalah?: number },
  createTasks?: boolean (default true),
  extraTasks?: { thermostat?: boolean, lights?: boolean }
}
*/
const b = items[0]?.json || {};
const apiBase = $env.SUKA_API_BASE || 'http://localhost:4000';
const lat = (b.lat != null) ? Number(b.lat) : Number($env.SABBATH_LAT || 41.8781);
const lon = (b.lon != null) ? Number(b.lon) : Number($env.SABBATH_LON || -87.6298);
const userId = b.userId || null;
const tz = b.tz || 'America/Chicago';

const envCandle = Number($env.SABBATH_CANDLE_OFFSET_MIN || 18);
const envPrep = Number($env.SABBATH_PREP_OFFSET_MIN || 30);
const envHavdalah = Number($env.SABBATH_HAVDALAH_OFFSET_MIN || 42);

const offsets = {
  candle: (b.offsets && b.offsets.candle != null) ? Number(b.offsets.candle) : envCandle,
  prep: (b.offsets && b.offsets.prep != null) ? Number(b.offsets.prep) : envPrep,
  havdalah: (b.offsets && b.offsets.havdalah != null) ? Number(b.offsets.havdalah) : envHavdalah
};

const createTasks = (b.createTasks === undefined) ? true : !!b.createTasks;
const extra = b.extraTasks || { thermostat: true, lights: true };
const anyDate = b.date ? new Date(b.date) : new Date();

return [{ json: { apiBase, lat, lon, userId, tz, offsets, createTasks, extra, anyDateISO: anyDate.toISOString() } }];

/* Determine this week's Friday and Saturday, merge server prefs */
function fridayOfWeek(d){ const x = new Date(d); const day = x.getDay(); const diff = (5 - day + 7) % 7; x.setDate(x.getDate() + diff); x.setHours(0,0,0,0); return x; }
function addDaysISO(dISO, days){ const d = new Date(dISO); d.setDate(d.getDate() + days); return d.toISOString().slice(0,10); }

const ctx = $json;
const pref = $items('HTTP: Get Preferences', 0, 0)[0]?.json || {};
const sabAware = !!(pref.calendar?.sabbathAware ?? true);
const prefOffset = Number(pref.calendar?.sabbathSunsetOffsetMin ?? ctx.offsets.prep);

const base = new Date(ctx.anyDateISO);
const fri = fridayOfWeek(base);
const sat = new Date(fri); sat.setDate(fri.getDate() + 1);

const friday = fri.toISOString().slice(0,10);
const saturday = sat.toISOString().slice(0,10);

return [{ json: { ...ctx, sabbathAware: sabAware, offsets: { ...ctx.offsets, prep: prefOffset }, friday, saturday } }];

/* Build candle-lighting / prep / havdalah times and tasks */
function addMinutes(iso, m){ const d = new Date(iso); d.setMinutes(d.getMinutes() + Number(m)); return d.toISOString(); }
function subMinutes(iso, m){ return addMinutes(iso, -Number(m)); }

function safeSunset(resp, fallbackISO){
  try { const r = resp?.results?.sunset || resp?.results?.sunsetISO || null; return r || fallbackISO; } catch { return fallbackISO; }
}

const ctx = $items('Function: Prep Dates + Prefs', 0, 0)[0].json;
if (!ctx.sabbathAware) {
  return [{ json: { ok: true, message: 'Sabbath-aware disabled in preferences; no tasks created.', tasks: [], ctx } }];
}

const friResp = $items('HTTP: Sunset (Friday)', 0, 0)[0]?.json || {};
const satResp = $items('HTTP: Sunset (Saturday)', 0, 0)[0]?.json || {};

const fallbackFri = new Date(`${ctx.friday}T18:00:00.000Z`).toISOString();
const fallbackSat = new Date(`${ctx.saturday}T19:00:00.000Z`).toISOString();
const friSunset = safeSunset(friResp, fallbackFri);
const satSunset = safeSunset(satResp, fallbackSat);

const candleTime = subMinutes(friSunset, ctx.offsets.candle);
const prepTime = subMinutes(friSunset, ctx.offsets.prep);
const havdalahTime = addMinutes(satSunset, ctx.offsets.havdalah);

const tasks = [
  { title: 'Sabbath prep: finish cooking & set warmers', category: 'sabbath', labels: ['sabbath','prep'], priority: 2, due: prepTime, meta: { fridaySunset: friSunset, offsets: ctx.offsets } },
  { title: 'Light candles', category: 'sabbath', labels: ['sabbath','candles'], priority: 1, due: candleTime, meta: { fridaySunset: friSunset, candleOffsetMin: ctx.offsets.candle } },
  { title: 'Havdalah', category: 'sabbath', labels: ['sabbath','havdalah'], priority: 2, due: havdalahTime, meta: { saturdaySunset: satSunset, havdalahOffsetMin: ctx.offsets.havdalah } }
];

if (ctx.extra?.thermostat) tasks.push({ title: 'Set thermostat to Sabbath mode', category: 'home', labels: ['sabbath','thermostat'], priority: 3, due: subMinutes(candleTime, 15), meta: {} });
if (ctx.extra?.lights) tasks.push({ title: 'Set light timers / scenes', category: 'home', labels: ['sabbath','lights'], priority: 3, due: subMinutes(candleTime, 20), meta: {} });

// attach for downstream
return [{ json: { ...ctx, friSunset, satSunset, candleTime, prepTime, havdalahTime, tasks } }];

const out = [];
for (const t of ($json.tasks || [])) out.push({ json: { ...t, userId: $json.userId, apiBase: $json.apiBase } });
return out.length ? out : [{ json: { skip: true } }];

const created = ($items('HTTP: Create Task', 0, 0) || []).length;
const ctx = $json;
return [{ json: { ok: true, friday: ctx.friday, saturday: ctx.saturday, candleTime: ctx.candleTime, prepTime: ctx.prepTime, havdalahTime: ctx.havdalahTime, tasksPlanned: (ctx.tasks||[]).length, tasksCreated: created } }];
